Create example files demonstrating different use cases:

```rust
// crates/bubbletea-macros/examples/counter.rs
//! Simple counter demonstrating basic #[derive(Model)] usage

use bubbletea::{run, Command};
use bubbletea_macros::Model;

enum Msg {
    Increment,
    Decrement,
    Quit,
}

#[derive(Model)]
struct Counter {
    #[state]
    count: i32,
}

impl Counter {
    #[init]
    fn init() -> (Self, Command<Msg>) {
        (Counter { count: 0 }, Command::none())
    }

    #[update]
    fn update(&mut self, msg: Msg) -> Command<Msg> {
        match msg {
            Msg::Increment => self.count = self.count.saturating_add(1),
            Msg::Decrement => self.count = self.count.saturating_sub(1),
            Msg::Quit => return Command::quit(),
        }
        Command::none()
    }

    #[view]
    fn view(&self) -> String {
        format!(
            "Count: {}\n\n\
             [+] Increment  [-] Decrement  [q] Quit",
            self.count
        )
    }
}

fn main() -> anyhow::Result<()> {
    run(Counter::init)
}
```

