#[test]
fn test_all_table_fixtures() {
    let fixtures_dir = Path::new("tests/conformance/fixtures/markdown");

    let mut passed = 0;
    let mut failed = Vec::new();

    for entry in fs::read_dir(fixtures_dir).unwrap() {
        let entry = entry.unwrap();
        let path = entry.path();

        if path.file_name().unwrap().to_string_lossy().contains("table") {
            let name = path.file_stem().unwrap().to_string_lossy();

            println!("Testing fixture: {}", name);

            let input = fs::read_to_string(&path).unwrap();
            let expected_path = format!(
                "tests/conformance/fixtures/go_outputs/{}.txt",
                name
            );

            if let Ok(expected) = fs::read_to_string(&expected_path) {
                let actual = render(&input);

                if compare_outputs(&expected, &actual) {
                    passed += 1;
                    println!("  PASS");
                } else {
                    failed.push(name.to_string());
                    println!("  FAIL");
                    println!("  Expected:\n{}", &expected[..100.min(expected.len())]);
                    println!("  Actual:\n{}", &actual[..100.min(actual.len())]);
                }
            }
        }
    }

    println!("\nResults: {}/{} passed", passed, passed + failed.len());

    assert!(
        failed.is_empty(),
        "Failed fixtures: {:?}",
        failed
    );
}
