#[test]
fn test_large_table_performance() {
    // Generate a large table
    let mut markdown = String::from("| ");
    for i in 0..10 {
        markdown.push_str(&format!("Col{} | ", i));
    }
    markdown.push('\n');

    markdown.push_str("|");
    for _ in 0..10 {
        markdown.push_str("----|");
    }
    markdown.push('\n');

    for row in 0..100 {
        markdown.push('|');
        for col in 0..10 {
            markdown.push_str(&format!(" R{}C{} |", row, col));
        }
        markdown.push('\n');
    }

    let start = std::time::Instant::now();
    let output = render(&markdown);
    let duration = start.elapsed();

    println!("Large table (100x10) rendered in {:?}", duration);

    assert!(duration.as_secs() < 2, "Table rendering too slow");
    assert!(output.contains("R99C9"), "Last cell should be present");
}
