    use bubbletea::{Model, Program, Cmd};
    use lipgloss::{Style, theme::{Theme, Preset, ThemeContext}};
    use std::sync::Arc;

    struct ThemedApp {
        context: Arc<ThemeContext>,
        button_style: Style,
        text_style: Style,
        render_count: usize,
    }

    enum Msg {
        SwitchTheme(Preset),
        ThemeChanged,
    }

    impl ThemedApp {
        fn new(preset: Preset) -> Self {
            let theme = Theme::from_preset(preset);
            let context = Arc::new(ThemeContext::new(theme));

            Self {
                button_style: Style::themed(&context)
                    .foreground_slot(ColorSlot::Primary)
                    .background_slot(ColorSlot::Surface),
                text_style: Style::themed(&context)
                    .foreground_slot(ColorSlot::Text),
                context,
                render_count: 0,
            }
        }
    }

    impl Model for ThemedApp {
        type Message = Msg;

        fn update(&mut self, msg: Msg) -> Cmd<Msg> {
            match msg {
                Msg::SwitchTheme(preset) => {
                    self.context.set_theme(Theme::from_preset(preset));
                    Cmd::message(Msg::ThemeChanged)
                }
                Msg::ThemeChanged => {
                    self.render_count += 1;
                    Cmd::none()
                }
            }
        }

        fn view(&self) -> String {
            format!(
                "{}\n{}",
                self.button_style.render("Button"),
                self.text_style.render("Text content")
            )
        }
    }

    #[test]
    fn test_theme_switch_updates_styles() {
        let mut app = ThemedApp::new(Preset::Dark);

        let dark_view = app.view();

        app.update(Msg::SwitchTheme(Preset::Light));

        let light_view = app.view();

        // Views should be different (different colors)
        assert_ne!(
            strip_ansi(&dark_view),
            strip_ansi(&light_view),
            "Theme switch should change output"
        );

        // Both should contain the text
        assert!(dark_view.contains("Button"));
        assert!(light_view.contains("Button"));
    }

    #[test]
    fn test_multiple_components_update_together() {
        let context = Arc::new(ThemeContext::new(Theme::from_preset(Preset::Dark)));

        let style1 = Style::themed(&context).foreground_slot(ColorSlot::Primary);
        let style2 = Style::themed(&context).foreground_slot(ColorSlot::Primary);

        let output1_dark = style1.render("A");
        let output2_dark = style2.render("B");

        // Switch theme
        context.set_theme(Theme::from_preset(Preset::Light));

        let output1_light = style1.render("A");
        let output2_light = style2.render("B");

        // Both should update consistently
        assert_ne!(output1_dark, output1_light);
        assert_ne!(output2_dark, output2_light);

        // Both should use the same new primary color
        let color1 = extract_fg_color(&output1_light);
        let color2 = extract_fg_color(&output2_light);
        assert_eq!(color1, color2, "Components should use same theme color");
    }
