### 4. Test Update Pattern
```rust
#[test]
fn test_code_block_rust_highlighting() {
    // Was: skip!("SyntaxHighlight not implemented");

    let markdown = r#"
```rust
fn main() {
    println!("Hello");
}
```
"#;

    let config = StyleConfig::default()
        .syntax_theme("base16-ocean.dark");
    let rendered = glamour::render_with_config(markdown, config);

    // Verify highlighting applied
    // Note: We check for ANSI escape codes indicating color
    assert!(rendered.contains("\x1b["), "Should contain ANSI color codes");

    // Verify key tokens are colored
    assert_contains_colored(&rendered, "fn");      // keyword
    assert_contains_colored(&rendered, "main");    // function name
    assert_contains_colored(&rendered, "\"Hello\""); // string
}

fn assert_contains_colored(output: &str, text: &str) {
    // Find text and verify it's preceded by color escape
    let pos = output.find(text).expect("Text not found");
    let before = &output[..pos];
    assert!(
        before.ends_with_ansi_color(),
        "Text '{}' should be colored",
        text
    );
}
```

